import React from 'react';
import { motion } from 'framer-motion';
import { Star, Heart, Users } from 'lucide-react';

const services = [
  {
    id: 1,
    title: "The Wedding Sangeet",
    icon: <Heart className="w-8 h-8 text-gold" />,
    desc: "Boutique choreography for couples, families, and friends. We turn your celebration into a cinematic visual story.",
    tags: ["Couples", "Family Groups", "Thematic Concepts"]
  },
  {
    id: 2,
    title: "Corporate Atelier",
    icon: <Users className="w-8 h-8 text-gold" />,
    desc: "Professional performance for product launches, award nights, and gala dinners. Sophisticated & High-energy.",
    tags: ["Product Launch", "Team Building", "Flash Mobs"]
  },
  {
    id: 3,
    title: "Artistic Direction",
    icon: <Star className="w-8 h-8 text-gold" />,
    desc: "Stage shows, music videos, and cinematic choreography. We bring professional-grade vision to your production.",
    tags: ["Music Videos", "TV Production", "Theater"]
  }
];

const ProServices = () => {
  return (
    <div className="pt-32 pb-24 px-6">
      <div className="max-w-7xl mx-auto">
        <div className="text-center mb-20">
          <h1 className="text-5xl font-cinzel mb-4">Pro Services</h1>
          <p className="text-gold tracking-widest uppercase text-sm">Excellence for your Special Moments</p>
        </div>

        <div className="grid lg:grid-cols-3 gap-12">
          {services.map((service, index) => (
            <motion.div
              key={service.id}
              initial={{ opacity: 0, scale: 0.95 }}
              whileInView={{ opacity: 1, scale: 1 }}
              transition={{ delay: index * 0.2 }}
              viewport={{ once: true }}
              className="bg-[#1A1A1A] border border-gold/10 p-10 hover:border-gold/40 transition-all group"
            >
              <div className="mb-8 group-hover:scale-110 transition-transform">{service.icon}</div>
              <h3 className="text-2xl font-cinzel text-ivory mb-4">{service.title}</h3>
              <p className="text-ivory/60 font-light mb-8 leading-relaxed">
                {service.desc}
              </p>
              <div className="flex flex-wrap gap-2">
                {service.tags.map(tag => (
                  <span key={tag} className="text-[10px] border border-ivory/20 px-3 py-1 uppercase tracking-widest text-gold">
                    {tag}
                  </span>
                ))}
              </div>
            </motion.div>
          ))}
        </div>

        <motion.div 
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          className="mt-20 p-12 text-center border-t border-gold/10"
        >
          <h2 className="text-3xl font-cinzel mb-6">Need a custom performance?</h2>
          <p className="max-w-2xl mx-auto text-ivory/70 mb-8 font-light italic">
            "Whether it's a grand wedding or a niche corporate event, we design movement that resonates."
          </p>
          <a href="/connect" className="gold-gradient px-12 py-4 text-charcoal font-bold uppercase tracking-widest text-sm rounded-sm">
            Book a Consultation
          </a>
        </motion.div>
      </div>
    </div>
  );
};

export default ProServices;
